const p = $json.payload || {};
let route = "", pageId = "", threadTs = "", channelId = "", promptTs = "", triggerId = "", round = 0, freeText = "";
let answers = {};
if (p.type === "view_submission") {
  route = "submit";
  let meta = {};
  try { meta = p.view && p.view.private_metadata ? JSON.parse(p.view.private_metadata) : {}; } catch (e) { meta = {}; }
  pageId = meta.pageId || ""; threadTs = meta.threadTs || ""; channelId = meta.channelId || ""; promptTs = meta.promptTs || ""; round = Number(meta.round || 0);
  const sv = (p.view && p.view.state && p.view.state.values) || {};
  const optAns = {}; const freeAns = {};
  Object.keys(sv).forEach(function (bid) {
    const el = sv[bid]; const akey = Object.keys(el)[0]; const v = el[akey];
    if (bid.indexOf("qf_") === 0) {
      const idx = bid.slice(3);
      if (v && v.value) { freeAns[idx] = v.value; }
    } else if (bid.indexOf("q_") === 0) {
      const idx = bid.slice(2);
      if (v && v.selected_option) { optAns[idx] = v.selected_option.value; }
      else if (v && v.selected_options) { optAns[idx] = v.selected_options.map(function (o) { return o.value; }).join(", "); }
      else if (v && v.value) { optAns[idx] = v.value; }
    }
  });
  const idxs = {};
  Object.keys(optAns).forEach(function (k) { idxs[k] = true; });
  Object.keys(freeAns).forEach(function (k) { idxs[k] = true; });
  Object.keys(idxs).forEach(function (idx) {
    const parts = [];
    if (optAns[idx]) { parts.push(optAns[idx]); }
    if (freeAns[idx]) { parts.push("(서술) " + freeAns[idx]); }
    answers[idx] = parts.join(" / ");
  });
} else if (p.type === "block_actions") {
  const a = (p.actions && p.actions[0]) || {};
  route = a.action_id || "";
  let val = {};
  try { val = a.value ? JSON.parse(a.value) : {}; } catch (e) { val = {}; }
  pageId = val.pageId || "";
  threadTs = (p.container && p.container.thread_ts) || (p.message && p.message.thread_ts) || "";
  channelId = (p.channel && p.channel.id) || (p.container && p.container.channel_id) || "";
  promptTs = (p.container && p.container.message_ts) || (p.message && p.message.ts) || "";
  triggerId = p.trigger_id || "";
}
return [{ json: { route: route, pageId: pageId, threadTs: threadTs, channelId: channelId, promptTs: promptTs, triggerId: triggerId, round: round, answers: JSON.stringify(answers), freeText: freeText } }];

const row = $json;
const norm = $("액션 정규화").first().json;
let qs = [];
try { qs = row.questions_json ? JSON.parse(row.questions_json) : []; } catch (e) { qs = []; }
const blocks = [];
qs.forEach(function (q, i) {
  const pfx = q.perspective ? ("[" + q.perspective + "] ") : "";
  const labelText = (pfx + "Q" + (i + 1) + ". " + q.text).slice(0, 150);
  const opts = (q.options || []).map(function (o) { return { text: { type: "plain_text", text: String(o).slice(0, 75), emoji: true }, value: String(o).slice(0, 150) }; });
  if (opts.length === 0) {
    blocks.push({ type: "input", block_id: ("q_" + i), optional: true, label: { type: "plain_text", text: labelText, emoji: true }, element: { type: "plain_text_input", action_id: "a", multiline: true } });
  } else {
    const element = q.multi ? { type: "checkboxes", action_id: "a", options: opts } : { type: "radio_buttons", action_id: "a", options: opts };
    blocks.push({ type: "input", block_id: ("q_" + i), optional: true, label: { type: "plain_text", text: labelText, emoji: true }, element: element });
