  type: "modal", callback_id: "answer_modal",
  private_metadata: JSON.stringify({ pageId: row.page_id, threadTs: row.thread_ts, channelId: row.channel_id, promptTs: norm.promptTs, round: Number(row.round || 0) }),
  title: { type: "plain_text", text: "기획 검토 답변" },
  submit: { type: "plain_text", text: "제출" },
  close: { type: "plain_text", text: "취소" },
